class Hesap {
  public sahip: string;
  private bakiye: number;

  constructor(sahip: string, bakiye: number) {
    this.sahip = sahip;
    this.bakiye = bakiye;
  }

  public paraYatir(miktar: number): void {
    this.bakiye += miktar;
  }

  public bakiyeGoster(): string {
    return `${this.sahip} bakiyesi: ${this.bakiye}`;
  }
}

const hesap = new Hesap("Ali", 1000);
hesap.paraYatir(500);
console.log(hesap.bakiyeGoster());

